class Solution:
    def longestString(self, x: int, y: int, z: int) -> int:
        # We can alternate between "AA" and "BB" as long as we don't have 2 of the same in a row
        # The maximum number of "AA" and "BB" we can use is 2 * min(x, y) + (1 if x != y else 0)
        # Each "AA" and "BB" contributes 2 to the length, and each "AB" contributes 2
        return 2 * (2 * min(x, y) + (1 if x != y else 0) + z)
